/* =========================================================================
 * Injection logic: read file, find each dict, insert entries before the
 * closing }; of each dict. Skip any slug already present.
 * ========================================================================= */

function escapeForRegex(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function injectEntries(src, dictName, entries) {
  // Find the dict declaration and its closing "};".
  // Strategy: find "const DICT_NAME = {" then find the matching close.
  const startMarker = `const ${dictName} = {`;
  const startIdx = src.indexOf(startMarker);
  if (startIdx === -1) {
    console.error(`  ERROR: could not find "${startMarker}" in source.`);
    return src;
  }

  // Walk forward from startIdx to find the matching close brace.
  // We count open/close braces and template-literal backticks.
  let braceDepth = 0;
  let inTemplateLiteral = false;
  let closeIdx = -1;
  for (let i = startIdx; i < src.length; i++) {
    const ch = src[i];
    if (ch === "`") {
      inTemplateLiteral = !inTemplateLiteral;
      continue;
    }
    if (inTemplateLiteral) continue;
    if (ch === "{") braceDepth++;
    if (ch === "}") {
      braceDepth--;
      if (braceDepth === 0) {
        closeIdx = i;
        break;
      }
    }
  }

  if (closeIdx === -1) {
    console.error(`  ERROR: could not find closing brace for "${dictName}".`);
    return src;
  }

  // Build the text to insert (before the closing }).
  let insertLines = [];
  let skipped = 0;
  for (const [slug, data] of Object.entries(entries)) {
    // Check if slug already exists in this dict region.
    const region = src.substring(startIdx, closeIdx);
    if (region.includes(`"${slug}"`)) {
      console.log(`  SKIP: "${slug}" already exists in ${dictName}.`);
      skipped++;
      continue;
    }

    // Build the entry.
    if (typeof data === "string") {
      // WARRANTY dict uses plain strings.
      insertLines.push(`  "${slug}": \`${data.replace(/`/g, "\\`")}\`,`);
    } else {
      // EXTRA / EXTRA2 dicts use objects.
      let objLines = [`  "${slug}": {`];
      for (const [key, val] of Object.entries(data)) {
        objLines.push(`    ${key}: \`${val.replace(/`/g, "\\`")}\`,`);
      }
      objLines.push(`  },`);
      insertLines.push(objLines.join("\n"));
    }
  }

  if (insertLines.length === 0) {
    console.log(`  All entries already present in ${dictName}. Nothing to inject.`);
    return src;
  }

  const insertion = "\n" + insertLines.join("\n") + "\n";
  const before = src.substring(0, closeIdx);
  const after = src.substring(closeIdx);
  console.log(`  INJECTED ${insertLines.length} entries into ${dictName} (skipped ${skipped}).`);
  return before + insertion + after;
}

// Main
let src = fs.readFileSync(TARGET, "utf8");
console.log(`Read ${TARGET} (${src.length} bytes)`);

src = injectEntries(src, "CITY_SIDING_EXTRA", NEW_EXTRA);
src = injectEntries(src, "CITY_SIDING_EXTRA2", NEW_EXTRA2);
src = injectEntries(src, "CITY_SIDING_WARRANTY", NEW_WARRANTY);

if (DRY) {
  console.log("\n--dry mode: not writing file.");
} else {
  fs.writeFileSync(TARGET, src, "utf8");
  console.log(`\nWrote ${TARGET} (${src.length} bytes)`);
}
